import os
import base64
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives import hashes
import logging

logger = logging.getLogger(__name__)


def _get_encryption_key() -> bytes:
    """
    Retrieve the encryption key from environment variables.
    
    The key must be set as an environment variable, NOT hardcoded in config files
    or source code. In production, use a secrets manager (AWS KMS, HashiCorp Vault,
    Azure Key Vault, etc.).
    """
    key_material = os.environ.get("CARD_ENCRYPTION_KEY")
    if not key_material:
        raise EnvironmentError(
            "CARD_ENCRYPTION_KEY environment variable is not set. "
            "Set it to a strong, randomly generated secret."
        )

    salt_str = os.environ.get("CARD_ENCRYPTION_SALT")
    if not salt_str:
        raise EnvironmentError(
            "CARD_ENCRYPTION_SALT environment variable is not set. "
            "Set it to a unique, randomly generated salt (base64-encoded, at least 16 bytes)."
        )

    salt = base64.urlsafe_b64decode(salt_str)
    if len(salt) < 16:
        raise ValueError("Encryption salt must be at least 16 bytes.")

    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=600_000,
    )
    derived_key = kdf.derive(key_material.encode("utf-8"))
    return base64.urlsafe_b64encode(derived_key)


def _validate_card_number(card_number: str) -> str:
    """Validate and sanitize a credit card number."""
    sanitized = card_number.replace(" ", "").replace("-", "")

    if not sanitized.isdigit():
        raise ValueError("Card number must contain only digits, spaces, or hyphens.")

    if not (13 <= len(sanitized) <= 19):
        raise ValueError("Card number must be between 13 and 19 digits.")

    return sanitized


def _luhn_check(card_number: str) -> bool:
    """Perform Luhn algorithm check on card number."""
    digits = [int(d) for d in card_number]
    digits.reverse()
    checksum = 0
    for i, d in enumerate(digits):
        if i % 2 == 1:
            d *= 2
            if d > 9:
                d -= 9
        checksum += d
    return checksum % 10 == 0


def encrypt_card_number(card_number: str) -> str:
    """
    Encrypt a credit card number using Fernet (AES-128-CBC with HMAC-SHA256).
    
    Returns a base64-encoded encrypted string suitable for database storage.
    Each encryption produces a unique ciphertext due to Fernet's use of
    a unique IV and timestamp per encryption.
    
    Args:
        card_number: The credit card number to encrypt.
        
    Returns:
        Base64-encoded encrypted card number string.
        
    Raises:
        ValueError: If the card number is invalid.
        EnvironmentError: If encryption keys are not configured.
    """
    sanitized = _validate_card_number(card_number)

    if not _luhn_check(sanitized):
        raise ValueError("Card number fails Luhn check.")

    key = _get_encryption_key()
    f = Fernet(key)
    encrypted = f.encrypt(sanitized.encode("utf-8"))

    logger.info(
        "Card number encrypted successfully (last four: ...%s)",
        sanitized[-4:]
    )

    return base64.urlsafe_b64encode(encrypted).decode("utf-8")


def decrypt_card_number(encrypted_card: str) -> str:
    """
    Decrypt an encrypted credit card number.
    
    This function should only be called in authorized contexts (e.g., refund processing).
    Access should be audited and restricted.
    
    Args:
        encrypted_card: The base64-encoded encrypted card number.
        
    Returns:
        The decrypted card number string.
        
    Raises:
        EnvironmentError: If encryption keys are not configured.
        cryptography.fernet.InvalidToken: If decryption fails (wrong key or tampered data).
    """
    if not encrypted_card or not isinstance(encrypted_card, str):
        raise ValueError("Encrypted card data must be a non-empty string.")

    key = _get_encryption_key()
    f = Fernet(key)

    encrypted_bytes = base64.urlsafe_b64decode(encrypted_card.encode("utf-8"))
    decrypted = f.decrypt(encrypted_bytes)
    card_number = decrypted.decode("utf-8")

    logger.info(
        "Card number decrypted for authorized operation (last four: ...%s)",
        card_number[-4:]
    )

    return card_number


def get_masked_card_number(card_number: str) -> str:
    """
    Return a masked version of a card number for display purposes.
    Only the last four digits are shown.
    
    Args:
        card_number: A plain or sanitized card number.
        
    Returns:
        Masked card number like '****-****-****-1234'.
    """
